#include <sql.h>
#include <sqlext.h>

SQLHENV henv;      // Environment handle
SQLHDBC hdbc;      // Connection handle
SQLRETURN retcode;

// Step 1: Allocate Environment Handle
SQLAllocHandle(SQL_HANDLE_ENV, SQL_NULL_HANDLE, &henv);
SQLSetEnvAttr(henv, SQL_ATTR_ODBC_VERSION, 
              (void*)SQL_OV_ODBC3, 0);

// Step 2: Allocate Connection Handle
SQLAllocHandle(SQL_HANDLE_DBC, henv, &hdbc);

// Step 3: Connect to Data Source
// Method A: Using SQLConnect
retcode = SQLConnect(hdbc,
    (SQLCHAR*)"MyDataSource", SQL_NTS,
    (SQLCHAR*)"username", SQL_NTS,
    (SQLCHAR*)"password", SQL_NTS);

// Method B: Using SQLDriverConnect (with dialog)
retcode = SQLDriverConnect(hdbc, NULL,
    (SQLCHAR*)"DSN=MyDataSource;UID=username;PWD=password;",
    SQL_NTS, NULL, 0, NULL, SQL_DRIVER_COMPLETE);

// Step 4: Use connected database...

// Step 5: Disconnect and Free Handles
SQLDisconnect(hdbc);
SQLFreeHandle(SQL_HANDLE_DBC, hdbc);
SQLFreeHandle(SQL_HANDLE_ENV, henv);

-- Query a view (same as querying a table)
SELECT * FROM EmployeeDetails;
SELECT * FROM DeptSalarySummary;

-- Check if view exists and view definition
SELECT * FROM information_schema.VIEWS 
WHERE TABLE_NAME = 'EmployeeDetails';

-- Modify view (recreate with new definition)
CREATE OR REPLACE VIEW EmployeeDetails AS
SELECT EmployeeID, FirstName, LastName, Department, Salary
FROM Employees
WHERE Department IN ('IT', 'HR');

-- Add WITH CHECK OPTION to prevent violations
CREATE VIEW ITEmployees AS
SELECT * FROM Employees WHERE Department = 'IT'
WITH CHECK OPTION;

-- Attempting to insert violating row will fail
INSERT INTO ITEmployees VALUES (101, 'John', 'Doe', 'Sales', 60000);
-- Error: The attempted insert or update failed

-- Drop a view
DROP VIEW EmployeeDetails;
DROP VIEW IF EXISTS DeptSalarySummary; -- PostgreSQL/MySQL 8.0+

-- Updatable view example
CREATE VIEW ITStaff AS
SELECT EmployeeID, FirstName, Salary
FROM Employees
WHERE Department = 'IT';

-- This INSERT works through updatable view
INSERT INTO ITStaff VALUES (999, 'NewEmp', 55000);
-- Equivalent to: INSERT INTO Employees VALUES (999, 'NewEmp', NULL, 55000, 'IT');
